thepet = pet("name", "Walter Hartwell White", 100, 100, 100, 100)
while thepet.hngr >= 0 and thepet.thrs >= 0 and thepet.hapyns >= 0:
    print("Choose your pet species from our selection:")
    print("Dog")
    print("Cat")
    print("Hamster")
    print("")
    thepet.name = input("Name your pet: ")
    thepet.terminal()
    print("")
    validcmd = 0
    while validcmd == 0:
        command = input().lower()
        validcmd = 1
        thepet.hygn -= 2
        if command == "feed":
            thepet.feedpet()
        elif command == "play":
            thepet.play()
        elif command == "water" or command == "give water":
            thepet.wateringthedog()
        elif command == "wash":
            thepet.wash()
        elif command == "do nothing" or command == "nothing":
            break
        elif command == "rename":
            thepet.rename()
            print("You bought a new nametag.")
        elif "waltuh" in command or "heisenburg" in command:
            thepet.hapyns += 100
            thepet.hngr += 100
            thepet.thrs += 100
            thepet.hygn -= 10
        else:
            print("Invalid command")
            validcmd = 0
            thepet.hygn += 2
    thepet.hngr -= random.randint(3, 5)
    thepet.thrs -= random.randint(3, 5)
    thepet.hapyns -= round((random.randint(2, 3) * ((1 + (1 - (thepet.hngr / 100)))**2)), 1)
    thepet.hapyns -= round((random.randint(1, 2) * ((1 + (1 - (thepet.hygn / 100)))**2)), 1)
    thepet.hygn -= 1
    if thepet.hapyns >= 100:
        thepet.hapyns = 100
    if thepet.wash >= 100:
        thepet.wash = 100
    if thepet.wash <= 0:
        thepet.wash = 0
    time.sleep(2)
if thepet.hngr <= 0:
    print(thepet.name, " starved to death.")
    time.sleep(5)
    print("⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⣀⠠⢄⡂⠖⡌⢆⠣⠜⣠⠣⠜⣠⠣⠜⢢⡑⢢⠔⡠⢄⡀⡀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀")
